import React, { useState } from "react";
import PropTypes from "prop-types";
import type { Accordion } from "../../types/tools/accordion";

function Finder__Accordion(props: Accordion) {
    const [isOpen, setIsOpen] = useState(false);

    const toggleAccordion = () => {
        setIsOpen(!isOpen);
    };
    
    if(props.matrixState){
        return (
            <div className="finder__accordion" data-matrix-state={props.matrixState}>
                <h3>{props.title}</h3>
                <div className="finder__accordion__content" data-open={isOpen}>
                    {props.children}
                </div>
            </div>
        );
    }
    else{
    return (
            <div className="finder__accordion">
                <h3>
                    <button
                        className="finder__accordion__toggle"
                        type="button"
                        aria-expanded={isOpen}
                        onClick={toggleAccordion}
                    >
                        {props.title} {props.totalChecked > 0 && <span className="finder__accordion__count">({props.totalChecked})</span>}
                    </button>
                </h3>
                <div className="finder__accordion__content" data-closed={!isOpen}>
                    {props.children}
                </div>
            </div>
        );
    }
}

Finder__Accordion.propTypes = {
    title: PropTypes.string.isRequired,
    children: PropTypes.node.isRequired,
    matrixState: PropTypes.bool.isRequired,
    totalChecked: PropTypes.number,
};

export default Finder__Accordion;